import React, { useState, useEffect } from 'react';
import {
  Chart as ChartJS,
  CategoryScale, LinearScale, PointElement, LineElement,
  BarElement, ArcElement, Title, Tooltip, Legend, Filler,
} from 'chart.js';
import { Line, Doughnut } from 'react-chartjs-2';
import StatsCard from '../components/StatsCard';
import { getStats, getSites } from '../services/api';

ChartJS.register(
  CategoryScale, LinearScale, PointElement, LineElement,
  BarElement, ArcElement, Title, Tooltip, Legend, Filler
);

const Dashboard = () => {
  const [stats, setStats] = useState({ total: 0, online: 0, offline: 0, files: 0 });
  const [sites, setSites] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [statsRes, sitesRes] = await Promise.all([getStats(), getSites()]);
        setStats(statsRes.data);
        setSites(sitesRes.data.sites || []);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // Uptime line chart (simulated last 7 days)
  const uptimeData = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Uptime %',
        data: [98.2, 99.1, 97.5, 99.8, 100, 99.3, stats.total > 0 ? (stats.online / stats.total * 100).toFixed(1) : 100],
        borderColor: '#6366f1',
        backgroundColor: 'rgba(99,102,241,0.08)',
        tension: 0.4,
        fill: true,
        pointBackgroundColor: '#6366f1',
        pointRadius: 4,
        pointHoverRadius: 6,
      },
    ],
  };

  const uptimeOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        backgroundColor: '#111827',
        borderColor: 'rgba(99,102,241,0.3)',
        borderWidth: 1,
        titleColor: '#f1f5f9',
        bodyColor: '#94a3b8',
        callbacks: { label: (ctx) => ` ${ctx.parsed.y}%` },
      },
    },
    scales: {
      x: {
        grid: { color: 'rgba(255,255,255,0.04)' },
        ticks: { color: '#475569', font: { family: 'Sora', size: 11 } },
      },
      y: {
        min: 90,
        max: 100,
        grid: { color: 'rgba(255,255,255,0.04)' },
        ticks: { color: '#475569', font: { family: 'Sora', size: 11 }, callback: (v) => `${v}%` },
      },
    },
  };

  // Status doughnut
  const doughnutData = {
    labels: ['Online', 'Offline', 'Unknown'],
    datasets: [{
      data: [
        stats.online,
        stats.offline,
        stats.total - stats.online - stats.offline,
      ],
      backgroundColor: ['rgba(16,185,129,0.8)', 'rgba(239,68,68,0.8)', 'rgba(245,158,11,0.5)'],
      borderColor: ['#10b981', '#ef4444', '#f59e0b'],
      borderWidth: 2,
    }],
  };

  const doughnutOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'bottom',
        labels: {
          color: '#94a3b8',
          font: { family: 'Sora', size: 12 },
          padding: 16,
          usePointStyle: true,
        },
      },
      tooltip: {
        backgroundColor: '#111827',
        borderColor: 'rgba(99,102,241,0.3)',
        borderWidth: 1,
        titleColor: '#f1f5f9',
        bodyColor: '#94a3b8',
      },
    },
    cutout: '70%',
  };

  const recentSites = [...sites].slice(0, 5);

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '40vh' }}>
        <div className="hm-spinner" style={{ width: '36px', height: '36px', borderWidth: '3px' }}></div>
      </div>
    );
  }

  return (
    <div>
      {/* Stats */}
      <div className="stats-grid">
        <StatsCard
          icon="bi-globe2"
          value={stats.total}
          label="Total Sites"
          color="var(--accent)"
          bgColor="rgba(99,102,241,0.12)"
        />
        <StatsCard
          icon="bi-check-circle"
          value={stats.online}
          label="Sites Online"
          color="var(--success)"
          bgColor="rgba(16,185,129,0.12)"
        />
        <StatsCard
          icon="bi-x-circle"
          value={stats.offline}
          label="Sites Offline"
          color="var(--danger)"
          bgColor="rgba(239,68,68,0.12)"
        />
        <StatsCard
          icon="bi-folder2"
          value={stats.files}
          label="Files Stored"
          color="var(--warning)"
          bgColor="rgba(245,158,11,0.12)"
        />
      </div>

      {/* Uptime rate banner */}
      {stats.total > 0 && (
        <div style={{
          background: 'linear-gradient(135deg, rgba(99,102,241,0.1), rgba(139,92,246,0.06))',
          border: '1px solid rgba(99,102,241,0.2)',
          borderRadius: 'var(--radius)',
          padding: '16px 24px',
          marginBottom: '28px',
          display: 'flex',
          alignItems: 'center',
          gap: '16px',
        }}>
          <div style={{ fontSize: '28px' }}>📊</div>
          <div>
            <div style={{ fontWeight: '700', fontSize: '20px', color: 'var(--accent)' }}>
              {((stats.online / stats.total) * 100).toFixed(1)}% uptime rate
            </div>
            <div style={{ fontSize: '13px', color: 'var(--text-muted)' }}>
              {stats.online} of {stats.total} sites currently online
            </div>
          </div>
        </div>
      )}

      {/* Charts */}
      <div className="row g-4 mb-4">
        <div className="col-lg-8">
          <div className="chart-card">
            <h6>Uptime History (Last 7 days)</h6>
            <div style={{ height: '200px' }}>
              <Line data={uptimeData} options={uptimeOptions} />
            </div>
          </div>
        </div>
        <div className="col-lg-4">
          <div className="chart-card">
            <h6>Sites Status</h6>
            <div style={{ height: '200px' }}>
              {stats.total > 0 ? (
                <Doughnut data={doughnutData} options={doughnutOptions} />
              ) : (
                <div className="empty-state" style={{ padding: '30px 0' }}>
                  <div className="empty-icon">🌐</div>
                  <p>No sites yet</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Recent sites */}
      <div className="chart-card">
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '16px' }}>
          <h6 style={{ margin: 0 }}>Recent Sites</h6>
          <a href="/sites" style={{ fontSize: '13px', color: 'var(--accent)', textDecoration: 'none', fontWeight: '500' }}>
            View all <i className="bi bi-arrow-right"></i>
          </a>
        </div>
        {recentSites.length === 0 ? (
          <div className="empty-state" style={{ padding: '30px 0' }}>
            <div className="empty-icon">🌐</div>
            <h5>No sites yet</h5>
            <p>Go to Sites to add your first domain</p>
          </div>
        ) : (
          <div>
            {recentSites.map((site) => (
              <div className="activity-item" key={site.id}>
                <div
                  className="activity-dot"
                  style={{
                    background: site.status === 'online' ? 'var(--success)' : site.status === 'offline' ? 'var(--danger)' : 'var(--warning)',
                  }}
                />
                <span className="activity-text font-mono">{site.domain}</span>
                <span style={{
                  fontSize: '11px',
                  padding: '3px 8px',
                  borderRadius: '20px',
                  background: site.status === 'online' ? 'rgba(16,185,129,0.12)' : 'rgba(239,68,68,0.12)',
                  color: site.status === 'online' ? 'var(--success)' : 'var(--danger)',
                  fontWeight: '600',
                  textTransform: 'uppercase',
                  letterSpacing: '0.3px',
                }}>
                  {site.status}
                </span>
                <span className="activity-time">
                  {site.last_checked ? new Date(site.last_checked).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }) : '–'}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
